INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '5b972440-b9f0-4f6d-beba-1b4694398227',
  '00000000-0000-0000-0000-000000000001',
  $escape$SvelteKit File-Based Routing Is Your Architecture — Not Just Your URL Map$escape$,
  $escape$Every directory under `src/routes/` in SvelteKit is a self-contained feature unit, not just a URL segment. The folder declares its own data contract (`+page.server.ts`), error boundary (`+error.svelte`), and layout inheritance (`+layout.svelte`) — the filesystem is your architecture.

The `load` function in `+page.server.ts` runs exclusively on the server, returning a typed `PageData` object inferred from `./$types`. Throw SvelteKit's `error()` helper inside `load` and the nearest `+error.svelte` up the route tree catches it automatically — no try/catch in the component.

SvelteKit has no `+loading.svelte`. Instead, return an unresolved `Promise` from `load` and use `{#await}` in `+page.svelte` for streamed, progressive rendering — the page shell arrives immediately while deferred data resolves.

Route groups like `(auth)/` let you wrap routes in a shared `+layout.svelte` (e.g., auth guard, different shell) without polluting the URL. The group name is invisible to the router.

The result: open any route folder and instantly know what data it fetches, how it fails, and how it renders — zero cross-file archaeology required.$escape$,
  $escape$// src/routes/dashboard/+page.server.ts
import { error } from '@sveltejs/kit';
import type { PageServerLoad } from './$types';

export const load: PageServerLoad = async ({ locals }) => {
  if (!locals.user) throw error(401, 'Unauthorized');

  return {
    profile: locals.user,
    stats: fetchStats(locals.user.id), // unresolved Promise → streamed
  };
};

// src/routes/dashboard/+page.svelte
// {#await data.stats}<Skeleton />{:then s}<Stats data={s} />{/await}$escape$,
  $escape$typescript$escape$,
