INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8c65b667-b83c-4d48-8efa-8f3abdaee7df',
  '00000000-0000-0000-0000-000000000001',
  $escape$SvelteKit Component Design — Keep the Server at the Root, Push Interactivity to the Leaves$escape$,
  $escape$SvelteKit doesn't have a `use client` directive, but the same architectural principle applies: load data on the server, hydrate only where interactivity is needed. Your `+page.server.ts` is your server boundary — it runs exclusively on the server and its return value flows as props into your component tree. The mistake is reaching for `onMount` or reactive stores at the layout or page level when the data could simply arrive from `load()`. Structure your tree so `+page.server.ts` owns all data fetching, `+page.svelte` is a thin shell that distributes props, and only leaf components — a `<LikeButton>`, a `<CommentInput>` — wire up event handlers, `writable` stores, or `onMount` for client-only effects. This lets SvelteKit stream and prerender the outer shell while deferring hydration cost to small, focused components. Guard any truly client-only initialization with `if (browser)` from `$app/environment` rather than sprinkling `onMount` everywhere. The result: faster TTI, smaller hydration surface, and a clear mental model of what runs where.$escape$,
  $escape$// +page.server.ts — server boundary, zero client JS
export const load = async ({ locals }) => {
  const posts = await db.query('SELECT * FROM posts ORDER BY created_at DESC');
  return { posts };
};

// +page.svelte — thin shell, no onMount, no stores
<script lang="ts">
  import LikeButton from '$lib/LikeButton.svelte'; // leaf: has interactivity
  const { data } = $props();
</script>

{#each data.posts as post}
  <article>
    <h2>{post.title}</h2>
    <LikeButton postId={post.id} initialCount={post.likes} />
  </article>
{/each}

// LikeButton.svelte — leaf component, client interactivity lives here
<script lang="ts">
  import { browser } from '$app/environment';
  let { postId, initialCount } = $props();
  let count = $state(initialCount);
  const like = async () => { count++; await fetch(`/api/posts/${postId}/like`, { method: 'POST' }); };
</script>
<button onclick={like}>{count} Likes</button>$escape$,
