INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'bea45e07-703c-4d6d-8bd3-1407319fa214',
  '00000000-0000-0000-0000-000000000001',
  $escape$SvelteKit Route Loaders — Kill the Waterfall Before the Component Renders$escape$,
  $escape$SvelteKit's `load` function in `+page.server.ts` runs on the server before your component mounts — data arrives with the HTML, not after. This eliminates the fetch-on-mount waterfall that plagues component-level data fetching. If a page needs a post and its author, fire both requests in parallel inside a single `load` using Promise.all or by returning multiple awaited calls — SvelteKit resolves them concurrently. The typed `data` prop lands in `+page.svelte` fully resolved, no loading spinners required for initial paint. Nest `+layout.server.ts` loaders for shared data like auth state; child `load` functions run in parallel with their parent layout loaders automatically. SvelteKit's enhanced `fetch` inside `load` is credential-forwarded, SSR-safe, and deduplicated — never reach for `fetch` inside `onMount` or `<script>` blocks for route-critical data. For client-side navigations, loaders re-run transparently via `invalidate()` or `invalidateAll()`, giving you fine-grained cache control without a state library.$escape$,
  $escape$// src/routes/posts/[id]/+page.server.ts
import type { PageServerLoad } from './$types';

export const load: PageServerLoad = async ({ params, fetch }) => {
  const [post, author] = await Promise.all([
    fetch(`/api/posts/${params.id}`).then(r => r.json()),
    fetch(`/api/users/${params.id}/author`).then(r => r.json()),
  ]);

  return { post, author };
};

// src/routes/posts/[id]/+page.svelte
<script lang="ts">
  let { data } = $props();
</script>
<h1>{data.post.title}</h1>
<p>by {data.author.name}</p>$escape$,
  $escape$typescript$escape$,
