INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b730d6e5-0990-4cb8-b947-e41a0f794980',
  '00000000-0000-0000-0000-000000000001',
  $escape$SvelteKit Error Handling — +error.svelte Boundaries, notFound(), and redirect()$escape$,
  $escape$SvelteKit's error model is route-segment-scoped. Drop a `+error.svelte` next to any `+page.svelte` or `+layout.svelte` and it catches errors thrown within that segment — without taking down the surrounding shell. If a segment lacks one, the error bubbles to the nearest ancestor `+error.svelte`, ultimately falling back to `src/routes/+error.svelte`.

Throw structured errors in `load` or form actions using `error(status, message)` from `@sveltejs/kit`. Use `notFound()` as a semantic shorthand for `error(404)`, and `redirect(303, '/path')` for post-auth or post-mutation flows — both are `throw`-based, so SvelteKit intercepts them before your `return` is ever evaluated.

Inside `+error.svelte`, `$page.error` exposes the thrown object and `$page.status` gives the HTTP code — no prop drilling, no try/catch in the component. The component still inherits parent layout data via `$page.data`, so your nav shell stays intact on error pages.

One footgun: errors thrown outside `load` — e.g., in a module-level utility — bypass the boundary entirely and surface as unhandled exceptions. Keep all throwing inside `load`, `actions`, or `hooks.server.ts` `handle`.$escape$,
  $escape$// src/routes/posts/[slug]/+page.server.ts
import { error, redirect, notFound } from '@sveltejs/kit';
import type { PageServerLoad } from './$types';

export const load: PageServerLoad = async ({ params, locals }) => {
  if (!locals.user) redirect(303, '/login');

  const post = await db.posts.findUnique({ where: { slug: params.slug } });
  if (!post) notFound();
  if (post.draft && !locals.user.isAdmin) error(403, 'Forbidden');

  return { post };
};

// src/routes/posts/[slug]/+error.svelte
// <script>
//   import { page } from '$app/stores';
// </script>
// <h1>{$page.status}</h1>
// <p>{$page.error?.message}</p>$escape$,
  $escape$typescript$escape$,
