INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fe434730-26c2-4f24-883b-cb5b1eb00dda',
  '00000000-0000-0000-0000-000000000001',
  $escape$SvelteKit Server Actions — Every formData Value Is Hostile Until Proven Otherwise$escape$,
  $escape$SvelteKit's `actions` export in `+page.server.ts` runs server-side only, but network reachability doesn't equal safety — every `request.formData()` value arrives as an untyped string from the wire. Validate with Zod before any DB write or downstream call. The `fail()` helper from `@sveltejs/kit` returns structured 4xx responses without throwing, keeping your action's happy path readable.

The env module system is where SvelteKit's trust model really shines. Secrets belong in `$env/static/private` or `$env/dynamic/private` — the bundler raises a hard build error if these are imported inside any client-evaluated module (`+page.ts`, `+layout.ts`, a component). Public configuration lives in `$env/static/public`. Never fall back to `process.env` directly: it bypasses SvelteKit's enforcement entirely and its behavior inside client bundles is undefined.

`load` in `+page.server.ts` carries the same obligations as actions. User-controlled inputs like `params.id` or `url.searchParams.get()` are trust-boundary values too — parse and narrow them with the same rigor before they touch business logic.$escape$,
  $escape$// src/routes/subscribe/+page.server.ts
import { fail } from '@sveltejs/kit';
import { z } from 'zod';
import { SENDGRID_API_KEY } from '$env/static/private';
import type { Actions } from './$types';

const schema = z.object({
  email: z.string().email().max(254),
});

export const actions: Actions = {
  default: async ({ request }) => {
    const raw = Object.fromEntries(await request.formData());
    const result = schema.safeParse(raw);
    if (!result.success) return fail(422, { errors: result.error.flatten() });
    await sendEmail(result.data.email, SENDGRID_API_KEY);
  },
};$escape$,
  $escape$typescript$escape$,
