INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '30f9b9af-c9ed-40b9-b26c-683e4dca9b21',
  '00000000-0000-0000-0000-000000000001',
  $escape$SvelteKit i18n — URL Locale vs Cookie, and Server-Side Detection$escape$,
  $escape$SvelteKit gives you two primary locale strategies: encode it in the URL (`/en/about`, `/fr/about`) or store it in a cookie. URL-based locale is SEO-friendly and stateless — ideal for public content. Cookie-based is cleaner for authenticated apps where locale is a user preference.

For URL routing, use a `[lang]` param segment and a `+layout.server.ts` to load translations. Read `params.lang` in `load()` and pass it down via `$page.data`.

For server-side detection without a URL param, use the `handle` hook in `hooks.server.ts`. Parse `event.request.headers.get('accept-language')` to extract the preferred locale, then either redirect to the localized route or set a `locale` cookie via `event.cookies.set()`. Always prefer `event.locals` to propagate the resolved locale to all `load()` functions downstream — avoids redundant header parsing per route.

Avoid mixing strategies: if your `load()` reads from both `params.lang` and a cookie, you'll get hydration mismatches on the client.$escape$,
  $escape$// src/hooks.server.ts
import type { Handle } from '@sveltejs/kit';

export const handle: Handle = async ({ event, resolve }) => {
  const cookieLocale = event.cookies.get('locale');
  const headerLocale = event.request.headers.get('accept-language')?.split(',')[0].slice(0, 2);
  const supported = ['en', 'fr', 'de'];

  const locale = supported.includes(cookieLocale ?? '') 
    ? cookieLocale! 
    : supported.includes(headerLocale ?? '') 
    ? headerLocale! 
    : 'en';

  event.locals.locale = locale;
  return resolve(event);
};$escape$,
  $escape$typescript$escape$,
