INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '07088e99-8968-4b3f-bfc2-8fb3a2dc4a16',
  '00000000-0000-0000-0000-000000000001',
  $escape$SvelteKit SSE — Streaming Server-Sent Events from Route Handlers into Svelte Stores$escape$,
  $escape$SvelteKit's `+server.ts` route handlers can stream SSE by returning a `Response` wrapping a `ReadableStream` with `Content-Type: text/event-stream`. The `start` callback receives a `ReadableStreamDefaultController` — enqueue raw SSE-formatted strings (`data: ...

`) directly. Return a cancel function from `start` to clean up timers or DB subscriptions when the client disconnects.

On the client, use the browser's native `EventSource` API pointed at your route, then pipe incoming messages into a Svelte `writable` store. Wrap the connection in `onMount` and return `source.close` as the cleanup function — Svelte's lifecycle handles disconnection on component destroy automatically.

For server-side load data coexisting with the stream, keep concerns separated: use `+page.server.ts` for initial hydration and SSE for deltas only. This avoids race conditions where the initial `load` and the first SSE event overwrite each other. If you need auth, validate the JWT inside the `GET` handler via `request.headers.get('cookie')` before opening the stream — `EventSource` sends cookies but ignores `credentials: 'include'` since it predates Fetch.$escape$,
  $escape$// src/routes/stream/+server.ts
import type { RequestHandler } from './$types';

export const GET: RequestHandler = () => {
  const stream = new ReadableStream({
    start(controller) {
      const tick = setInterval(
        () => controller.enqueue(`data: ${JSON.stringify({ ts: Date.now() })}\n\n`),
        2000
      );
      return () => clearInterval(tick);
    }
  });
  return new Response(stream, {
    headers: { 'Content-Type': 'text/event-stream', 'Cache-Control': 'no-cache' }
  });
};$escape$,
